import sys
from functools import lru_cache

class Solution:
    def countNoZeroPairs(self, n):
        digits = [int(c) for c in str(n)][::-1]
        L = len(digits)
        sys.setrecursionlimit(100000)

        @lru_cache(maxsize=None)
        def dp(pos, carry, a_active, b_active):
            if pos == L + 1:
                return 1 if carry == 0 and not a_active and not b_active else 0
            target = digits[pos] if pos < L else 0
            total = 0
            da_opts = range(1, 10) if a_active else (0,)
            db_opts = range(1, 10) if b_active else (0,)
            for da in da_opts:
                for db in db_opts:
                    s = da + db + carry
                    if s % 10 != target:
                        continue
                    nc = s // 10
                    na_choices = (True, False) if a_active else (False,)
                    nb_choices = (True, False) if b_active else (False,)
                    for na in na_choices:
                        for nb in nb_choices:
                            total += dp(pos + 1, nc, na, nb)
            return total

        res = dp(0, 0, True, True)
        dp.cache_clear()
        return res

