var countNoZeroPairs = function(n) {
    const digits = String(n).split('').map(Number).reverse();
    const L = digits.length;
    const memo = new Map();
    function dp(pos, carry, aActive, bActive) {
        if (pos === L + 1) {
            return (carry === 0 && !aActive && !bActive) ? 1 : 0;
        }
        const key = pos + ',' + carry + ',' + (aActive ? 1 : 0) + ',' + (bActive ? 1 : 0);
        if (memo.has(key)) return memo.get(key);
        const target = pos < L ? digits[pos] : 0;
        let total = 0;
        const daOpts = aActive ? [1, 2, 3, 4, 5, 6, 7, 8, 9] : [0];
        const dbOpts = bActive ? [1, 2, 3, 4, 5, 6, 7, 8, 9] : [0];
        for (const da of daOpts) {
            for (const db of dbOpts) {
                const s = da + db + carry;
                if (s % 10 !== target) continue;
                const nc = Math.floor(s / 10);
                const naChoices = aActive ? [true, false] : [false];
                const nbChoices = bActive ? [true, false] : [false];
                for (const na of naChoices) {
                    for (const nb of nbChoices) {
                        total += dp(pos + 1, nc, na, nb);
                    }
                }
            }
        }
        memo.set(key, total);
        return total;
    }
    return dp(0, 0, true, true);
};
